mapper.select:
select t.*, m.name as movie_name, c.name as cinema_name, h.name as hall_name, s.show_date, s.show_time from ticket t left join schedule s on t.schedule_id = s.id left join movie m on s.movie_id = m.id left join cinema c on s.cinema_id = c.id left join hall h on s.hall_id = h.id
and t.number like concat('%', #{number}, '%')
and t.status = #{status}
and t.user_id = #{userId}
and t.order_time >= #{beginTime}
and t.order_time <= #{endTime}
order by t.order_time desc
